// checavuelos — Buscar vuelos via SerpAPI (8 calls optimizadas)
// Combina MID,CUN en una sola llamada para reducir 16 → 8 calls

const config = $input.first().json;
const API_KEY = config.serpApiKey;

if (!API_KEY) {
  return [{ json: { error: 'SERPAPI_KEY not configured', outbound: [], returns: [], roundtrips: [] } }];
}

// --- Config de rutas ---
const COMBINED_ORIGINS = 'MID,CUN';
const DESTINATIONS = 'FCO,FLR,PSA,MXP,CDG,ORY';
const RETURN_ORIGINS = 'FCO,FLR,PSA,MXP,BGY,NAP,VCE';
const OUTBOUND_DATES = ['2026-09-24', '2026-09-25', '2026-09-26', '2026-09-27'];
const RETURN_DATES = ['2026-10-12', '2026-10-13', '2026-10-14'];
const RT_OUTBOUND = '2026-09-25';
const RT_RETURN = '2026-10-12';

// --- SerpAPI helper ---
async function searchFlights(params) {
  const qs = new URLSearchParams({
    engine: 'google_flights',
    ...params,
    hl: 'es',
    gl: 'mx',
    currency: 'MXN',
    sort_by: '2',
    api_key: API_KEY,
  });
  const url = `https://serpapi.com/search?${qs.toString()}`;
  const res = await this.helpers.httpRequest({ method: 'GET', url, timeout: 30000 });
  return typeof res === 'string' ? JSON.parse(res) : res;
}

// --- Procesar resultados one-way ---
function processResults(serpData) {
  const flights = [];
  const bestFlights = serpData?.best_flights || [];
  const otherFlights = serpData?.other_flights || [];
  const all = [...bestFlights, ...otherFlights];

  for (const flight of all.slice(0, 15)) {
    const legs = flight.flights || [];
    if (!legs.length) continue;
    const first = legs[0];
    const last = legs[legs.length - 1];
    const airlines = [...new Set(legs.map(l => l.airline))].join(', ');
    const fromCode = first.departure_airport?.id || '';
    const toCode = last.arrival_airport?.id || '';

    flights.push({
      from: fromCode,
      from_city: first.departure_airport?.name || fromCode,
      to: toCode,
      to_city: last.arrival_airport?.name || toCode,
      airlines,
      departure: first.departure_airport?.time || '',
      arrival: last.arrival_airport?.time || '',
      stops: legs.length - 1,
      duration_h: Math.round((flight.total_duration || 0) / 60 * 10) / 10,
      price_usd: flight.price || 0,
      deep_link: `https://www.google.com/travel/flights?q=flights+from+${fromCode}+to+${toCode}`,
      is_best: bestFlights.includes(flight),
    });
  }
  flights.sort((a, b) => a.price_usd - b.price_usd);
  return flights.slice(0, 10);
}

// --- Procesar resultados round-trip ---
function processRoundtrip(serpData) {
  const flights = [];
  const bestFlights = serpData?.best_flights || [];
  const otherFlights = serpData?.other_flights || [];
  const all = [...bestFlights, ...otherFlights];

  for (const flight of all.slice(0, 10)) {
    const legs = flight.flights || [];
    if (!legs.length) continue;
    const first = legs[0];
    const last = legs[legs.length - 1];
    const airlines = [...new Set(legs.map(l => l.airline))].join(', ');
    const fromCode = first.departure_airport?.id || '';
    const toCode = last.arrival_airport?.id || '';

    flights.push({
      from: fromCode,
      from_city: first.departure_airport?.name || fromCode,
      to: toCode,
      to_city: last.arrival_airport?.name || toCode,
      airlines,
      departure: first.departure_airport?.time || '',
      arrival: last.arrival_airport?.time || '',
      stops: legs.length - 1,
      duration_h: Math.round((flight.total_duration || 0) / 60 * 10) / 10,
      price_usd: flight.price || 0,
      deep_link: `https://www.google.com/travel/flights?q=flights+from+${fromCode}+to+${toCode}`,
      is_best: bestFlights.includes(flight),
      type: 'roundtrip',
    });
  }
  flights.sort((a, b) => a.price_usd - b.price_usd);
  return flights.slice(0, 10);
}

// --- Dedup ---
function dedup(flights) {
  const seen = new Map();
  for (const f of flights) {
    const key = `${f.from}-${f.to}-${f.airlines}-${f.departure}`;
    if (!seen.has(key) || f.price_usd < seen.get(key).price_usd) seen.set(key, f);
  }
  return [...seen.values()].sort((a, b) => a.price_usd - b.price_usd);
}

// === EJECUTAR BUSQUEDAS (8 calls) ===
const errors = [];

// 4 outbound: MID,CUN → destinos x 4 fechas
const rawOutbound = [];
for (const date of OUTBOUND_DATES) {
  try {
    const data = await searchFlights.call(this, {
      departure_id: COMBINED_ORIGINS,
      arrival_id: DESTINATIONS,
      outbound_date: date,
      type: '2',
    });
    rawOutbound.push(...processResults(data));
  } catch (e) {
    errors.push(`outbound ${date}: ${e.message}`);
  }
}

// 3 return: origenes Europa → MID,CUN x 3 fechas
const rawReturns = [];
for (const date of RETURN_DATES) {
  try {
    const data = await searchFlights.call(this, {
      departure_id: RETURN_ORIGINS,
      arrival_id: COMBINED_ORIGINS,
      outbound_date: date,
      type: '2',
    });
    rawReturns.push(...processResults(data));
  } catch (e) {
    errors.push(`return ${date}: ${e.message}`);
  }
}

// 1 round-trip: MID,CUN → destinos
const rawRoundtrips = [];
try {
  const data = await searchFlights.call(this, {
    departure_id: COMBINED_ORIGINS,
    arrival_id: DESTINATIONS,
    outbound_date: RT_OUTBOUND,
    return_date: RT_RETURN,
    type: '1',
  });
  rawRoundtrips.push(...processRoundtrip(data));
} catch (e) {
  errors.push(`roundtrip: ${e.message}`);
}

// Dedup y limitar
const outbound = dedup(rawOutbound).slice(0, 15);
const returns = dedup(rawReturns).slice(0, 15);
const roundtrips = dedup(rawRoundtrips).slice(0, 10);

// Calcular best combo para evaluacion de alerta
const bestOut = outbound[0] || null;
const bestRet = returns[0] || null;
const bestRT = roundtrips[0] || null;
const comboPrice = (bestOut && bestRet) ? bestOut.price_usd + bestRet.price_usd : Infinity;
const rtPrice = bestRT?.price_usd || Infinity;
const bestPrice = Math.min(comboPrice, rtPrice);

return [{
  json: {
    outbound,
    returns,
    roundtrips,
    bestPrice: bestPrice === Infinity ? null : bestPrice,
    api_calls: 8,
    errors: errors.length ? errors : undefined,
  }
}];
